from src.infrastructure.config import require_local_uri, ConfigError

# Test cases
test_cases = [
    ("postgresql://localhost:5432/hcgrc", True, "standard localhost"),
    ("postgresql://127.0.0.1:5432/hcgrc", True, "IPv4 loopback"),
    ("postgresql://[::1]:5432/hcgrc", True, "IPv6 loopback"),
    ("postgresql://example.com:5432/hcgrc", False, "remote hostname"),
    ("postgresql://[REDACTED]:5432/hcgrc", False, "private IP"),
    ("sqlite:///tmp/data.db", True, "sqlite file (always local)"),
    ("/relative/path", True, "bare relative path (always local)"),
    ("postgresql://0.0.0.0:5432/hcgrc", False, "0.0.0.0 wildcard (should reject)"),
]

for uri, should_pass, description in test_cases:
    try:
        result = require_local_uri(uri, "test")
        if should_pass:
            print(f"PASS: {description}: {uri}")
        else:
            print(f"FAIL: {description} should have raised but got: {uri}")
    except ConfigError as e:
        if not should_pass:
            print(f"PASS: {description} correctly rejected")
        else:
            print(f"FAIL: {description} should have passed but got error: {e}")
EOFTEST
